using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class GroupConfiguration : IEntityTypeConfiguration<Group>{public void Configure(EntityTypeBuilder<Group> builder){builder.ToTable("groups");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("group_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.Name).HasMaxLength(100).IsRequired();builder.Property(e => e.InviteCode).HasMaxLength(20).IsRequired();builder.Property(e => e.GroupType).HasConversion<string>().HasMaxLength(20);builder.Property(e => e.ColorTheme).HasMaxLength(7);builder.HasOne(e => e.ParentGroup).WithMany(g => g.ChildGroups).HasForeignKey(e => e.ParentGroupId).OnDelete(DeleteBehavior.Restrict);builder.HasOne(e => e.CreatedByUser).WithMany().HasForeignKey(e => e.CreatedByUserId);builder.HasIndex(e => e.InviteCode).IsUnique();builder.HasQueryFilter(e => e.DeletedAt == null);}}
